import React, { useEffect, useState } from "react";
import axios from "axios";
import { Container, Card, CardContent, Typography, Button, Grid, TextField } from "@mui/material";

const Menu = () => {
  const [menuItems, setMenuItems] = useState([]);
  const [newItem, setNewItem] = useState({
    name: "",
    description: "",
    price: "",
    category: "",
  });

  // Fetch menu items from the backend
  useEffect(() => {
    axios
      .get("http://localhost:8000/menu")
      .then((response) => {
        setMenuItems(response.data);
      })
      .catch((error) => {
        console.error("There was an error fetching the menu!", error);
      });
  }, []);

  // Handle form field changes
  const handleChange = (e) => {
    const { name, value } = e.target;
    setNewItem({
      ...newItem,
      [name]: value,
    });
  };

  // Handle form submission to add a new menu item
  const handleSubmit = (e) => {
    e.preventDefault();

    axios
      .post("http://localhost:8000/menu", newItem)
      .then((response) => {
        setMenuItems([...menuItems, response.data]);
        setNewItem({ name: "", description: "", price: "", category: "" });
      })
      .catch((error) => {
        console.error("There was an error adding the menu item!", error);
      });
  };

  return (
    <Container sx={{ marginTop: 4 }}>
      <Typography variant="h3" gutterBottom align="center">
        Menu
      </Typography>

      {/* Add Menu Item Form */}
      <form onSubmit={handleSubmit} style={{ marginBottom: "20px" }}>
        <TextField
          label="Name"
          variant="outlined"
          fullWidth
          name="name"
          value={newItem.name}
          onChange={handleChange}
          required
          style={{ marginBottom: "10px" }}
        />
        <TextField
          label="Description"
          variant="outlined"
          fullWidth
          name="description"
          value={newItem.description}
          onChange={handleChange}
          required
          style={{ marginBottom: "10px" }}
        />
        <TextField
          label="Price"
          variant="outlined"
          fullWidth
          name="price"
          value={newItem.price}
          onChange={handleChange}
          required
          style={{ marginBottom: "10px" }}
        />
        <TextField
          label="Category"
          variant="outlined"
          fullWidth
          name="category"
          value={newItem.category}
          onChange={handleChange}
          required
          style={{ marginBottom: "10px" }}
        />
        <Button type="submit" variant="contained" color="primary">
          Add Item
        </Button>
      </form>

      {/* Display Menu Items */}
      <Grid container spacing={3}>
        {menuItems.length === 0 ? (
          <Typography variant="h5" color="textSecondary" align="center" sx={{ width: "100%" }}>
            No menu items available.
          </Typography>
        ) : (
          menuItems.map((item) => (
            <Grid item xs={12} sm={6} md={4} key={item._id}>
              <Card sx={{ maxWidth: 345 }}>
                <CardContent>
                  <Typography variant="h5" component="div">
                    {item.name}
                  </Typography>
                  <Typography variant="body2" color="text.secondary" sx={{ marginTop: 1 }}>
                    {item.description}
                  </Typography>
                  <Typography variant="h6" color="primary" sx={{ marginTop: 1 }}>
                    Price: ${item.price}
                  </Typography>
                  <Typography variant="body2" color="text.secondary" sx={{ marginTop: 1 }}>
                    Category: {item.category}
                  </Typography>
                </CardContent>
              </Card>
            </Grid>
          ))
        )}
      </Grid>
    </Container>
  );
};

export default Menu;
